def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 45.0 + np.exp(-cap / 10) * 40 + np.sqrt(cap) * 18
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.3) - 150 * np.sin(cap * 2.2)
            if cap > 15:
                base_priority += 120 * np.log1p(cap) * np.cos(np.sqrt(cap))
            else:
                base_priority -= 50 * usage ** 1.5
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.75) * 25 / (i + 1)
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2200 * delta ** 2 + 300 * np.tanh(delta)
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.1)) * 30 / (j + 1)
            if int(cap * 4) % 5 == 1:
                base_priority += 60 * np.tan(cap / 18)
        elif 3 < usage <= 4:
            base_priority += 1500 * (usage - 3) ** 2.5
            for k in range(1, 15):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 12 / (k + 1)
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 11 and usage > 3.5:
                        fluctuation += 30
            if cap % 3.7 < 0.7:
                base_priority += 45 * np.sin(cap * 3.3)
        elif 2 < usage <= 3:
            base_priority += 1100 * (usage - 2) ** 3
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.7:
                    fluctuation += pwr * 20 / (m + 1)
                    if m % 2 == 1:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 2)
                    if m == 17 and usage > 2.6:
                        fluctuation += 25
            if cap % 1.9 < 0.6:
                base_priority += 40 * np.cos(cap * 2.7)
        elif 1 < usage <= 2:
            base_priority += 850 * (usage - 1) ** 4
            for n in range(1, 18):
                pwr = usage ** n
                if pwr < 0.8:
                    fluctuation += pwr * 30 / (n + 1)
                    if n % 4 == 3:
                        fluctuation -= 4 * n
                else:
                    fluctuation += (1 - pwr) * 18 / (n + 3)
                    if n == 15 and usage > 1.8:
                        fluctuation += 20
            if cap % 1.2 < 0.4:
                base_priority += 33 * np.cos(cap * 2.5)
        elif 0.4 < usage <= 1:
            base_priority += 150 * (1 - usage) ** 2.5 + np.sqrt(usage) * 20
            for o in range(1, 14):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / (o + 1)
                if usage < 0.08 * o:
                    fluctuation -= 10 * o
            if cap < 0.12:
                base_priority += np.sqrt(cap) * 300
            elif cap < 0.92:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 7) * 26
        else:
            base_priority += 320 * (1 - usage) ** 2
            for p in range(1, 22):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 5) - 0.22) * 15 / (p + 1)
                if usage < 0.02 * p:
                    fluctuation -= 14 * p
            if cap < 0.02:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.0:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 32
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 90
            if usage > 0.8:
                priority += 110
            elif usage < 0.1:
                priority -= 55
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.2:
            priority += 50
            if usage > 0.9:
                priority += 75
            elif usage < 0.25:
                priority -= 35
            for s in range(1, 8):
                if int(cap * 1400) % (s + 6) == 0:
                    priority += s * 9
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.96:
                priority += 110
                for u in range(1, 7):
                    priority += u * 12
            else:
                priority += 40
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 18
        if int(cap * 1000) % 27 == 0:
            proximity -= 13
        if int(cap * 220) % 11 == 0:
            proximity += 16
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.015:
                proximity += 25 / w
            elif diff < 0.04:
                proximity += 13 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1800) % (x + 11)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1800) % (y + 8)
            if mod_chk == 0:
                proximity += 12 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.004:
            for z in range(1, 10):
                priority -= z * 12
        elif usage > 0.97:
            for aa in range(1, 8):
                priority += aa * 15
        if cap > 3.0:
            if cap % 1.2 < 0.07:
                priority += 50
            if (int(cap * 2800) % 29 == 0) and (usage > 0.75):
                priority += 75
            for bb in range(1, 8):
                if (int(cap * 720) % (bb + 11) == 3) and (usage < 0.9):
                    priority -= 35
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
